mapper.select:
SELECT id, application_case_id, job_posting_id, user_id, source_type, status, error_message, extraction_strategy, quality_score, quality_status, quality_report_json, model_versions_json, fallback_eligible, fallback_reason, reviewed_at, started_at, finished_at, created_at, updated_at FROM ( SELECT e.*, ROW_NUMBER() OVER ( PARTITION BY e.application_case_id ORDER BY e.created_at DESC, e.id DESC ) AS rn FROM application_case_extraction e INNER JOIN application_case ac ON ac.id = e.application_case_id WHERE ac.user_id = #{userId} AND ac.deleted_at IS NULL AND e.application_case_id IN
#{applicationCaseId}
) latest WHERE rn = 1 ORDER BY created_at DESC, id DESC
